return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n > 1);','language'=>'fr_FR','project-id-version'=>'PublishPress Future Pro','pot-creation-date'=>'2024-07-02T17:41:26+00:00','po-revision-date'=>'2024-07-10 00:28+0200','x-generator'=>'Poedit 3.4.4','messages'=>['PublishPress Future Pro'=>'PublishPress Future Pro','http://wordpress.org/extend/plugins/post-expirator/'=>'http://wordpress.org/extend/plugins/post-expirator/','PublishPress Future allows you to schedule automatic changes to posts, pages and other content types.'=>'PublishPress Future vous permet de programmer des modifications automatiques des publications, des pages et d’autres types de publication.','PublishPress'=>'PublishPress','http://publishpress.com'=>'http://publishpress.com','Post expires at #ACTIONTIME on #ACTIONDATE.'=>'La publication expire à #ACTIONTIME le #ACTIONDATE.','F j, Y'=>'j F Y','g:i a'=>'G\\hi','Displays a message with the date and time of the future action.'=>'Afficher un message avec la date et l’heure de l’action future.','Type the text template and use # to see the autocomplete options with the available placeholders.'=>'Saisir le modèle de texte et utiliser # pour voir les options de complétion automatique avec les textes indicatifs disponibles.','Available placeholders'=>'Les textes indicatifs disponibles','Future action block template. Type the text and # to see the autocomplete options.'=>'Modèle de bloc d’action Future. Saisir le texte et # pour voir les options de complétion automatique.','Action time'=>'Temps d’action','Action date'=>'Date de l’action','Custom statuses'=>'États personnalisés','Enable custom statuses for the post type.'=>'Activer les états personnalisés pour le type de publication','Enabled'=>'Activé','Disabled'=>'Désactivée','Select all'=>'Tout sélectionner','Unselect all'=>'Tout désélectionner','Enable Metadata Scheduling'=>'Activer la planification des métadonnées','Enable metadata scheduling for the post type'=>'Activer la planification des métadonnées pour le type de publication','Checking this option will allow you to use the post metadata to control the scheduling of Future actions in your content.'=>'En cochant cette option, vous pourrez utiliser les métadonnées de la publication pour contrôler la planification des actions de Future dans votre contenu.','Metadata Mapping'=>'Mappage de métadonnées','To use the default mapping, please leave the fields empty.'=>'Pour utiliser le mappage par défaut, veuillez laisser les champs vides.','Read more about metadata mapping.'=>'En savoir plus sur le mappage des métadonnées.','Original Metakey'=>'Metakey original','New Metakey'=>'Nouvelle metakey','Description'=>'Description','Hide Future metabox for this post type'=>'Masquer la boîte méta de Future pour ce type de publication','Checking this option will disable the PublishPress Future metabox. This can prevent conflicts if you\'re using Metadata Scheduling with plugins such as ACF or Pods.'=>'En cochant cette option, la boîte méta de PublishPress Future sera désactivée. Cela permet d’éviter les conflits si vous utilisez la planification des métadonnées avec des extensions telles que ACF ou Pods.','Action Date (Required)'=>'Date de l’action (obligatoire)','The date used for scheduling the action. The date must be a unix time stamp or in the \'Y-m-d H:i:s\' format.'=>'La date utilisée pour planifier l’action. La date doit être un horodatage Unix ou au format ’Y-m-d H:i:s’.','Action Type'=>'Type d’action','The type of action to be performed.'=>'Le type d’action à exécuter.','New Post Status'=>'État de la nouvelle publication','The new post status to be applied to the post.'=>'Le nouveau état de la publication à appliquer à la publication.','Action Status'=>'État de l’action','The status for the action. Anything different than \'saved\' will be considered as not active.'=>'L’état de l’action. Tout ce qui n’est pas « enregistré » sera considéré comme non actif.','Taxonomy Name'=>'Nom de la taxonomie','The taxonomy